import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
// Adjusted paths assuming 'pages' directory is a sibling to where App.js resides (e.g., if App.js is in 'src' and 'pages' is also in 'src')
import SignIn from '../pages/SignIn.jsx'; // Admin SignIn
import SignUp from '../pages/SignUp.jsx'; // Admin SignUp
import UserSignIn from '../pages/UserSignIn.jsx'; // New User SignIn
import UserSignUp from '../pages/UserSignUp.jsx'; // New User SignUp
import Question from '../pages/Question.jsx';
import PaperSetPage from '../pages/PaperSetPage.jsx';
import AnswerPage from '../pages/AnswerPage.jsx'; // Exam page for users

function App() {
  return (
    <Router>
      <Routes>
        {/* Default route (can be login or homepage) */}
        <Route path="/" element={<UserSignIn />} />

        {/* Admin related routes */}
        <Route path="/admin-signin" element={<SignIn />} /> {/* Renamed for clarity */}
        <Route path="/admin-signup" element={<SignUp />} /> {/* Renamed for clarity */}
        <Route path="/question" element={<Question />} /> {/* Question setter page */}
        <Route path="/paper-set" element={<PaperSetPage />} /> {/* Moderator page */}

        {/* User related routes */}
        <Route path="/user-signin" element={<UserSignIn />} />
        <Route path="/user-signup" element={<UserSignUp />} />
        <Route path="/exam" element={<AnswerPage />} /> {/* User's exam page */}

        {/* Add any other general routes here */}
      </Routes>
    </Router>
  );
}

export default App;
